SELECT * FROM public."SoilDatas"
WHERE "SoilDataID" = #{soilDataID}
  AND "IsDelete" = false

    SELECT * FROM public."SoilDatas"
    WHERE "IsDelete" = false
WHERE year = #{year}
LIMIT #{pageSize} OFFSET #{offset};

SELECT COUNT(1) FROM public."SoilDatas" s JOIN public."MonitoringPoints" mp ON mp."MonitoringPointID" = s."MonitoringPointID"
s."IsDelete" = false
AND mp."CountyDistrict" = #{countyDistrict}

SELECT s.* FROM public."SoilDatas" s JOIN public."MonitoringPoints" mp ON mp."MonitoringPointID" = s."MonitoringPointID"
s."IsDelete" = false
AND mp."CountyDistrict" = #{countyDistrict}
ORDER BY s."SoilDataID" ASC LIMIT #{limit} OFFSET #{offset}
